import React, { useState, useCallback } from 'react';
import { useDropzone } from 'react-dropzone';
import axios from 'axios';
import { Upload, Shield, Download } from 'lucide-react';

export default function Evidence() {
  const [file,       setFile]       = useState(null);
  const [preview,    setPreview]    = useState(null);
  const [name,       setName]       = useState('');
  const [incident,   setIncident]   = useState('');
  const [loading,    setLoading]    = useState(false);
  const [result,     setResult]     = useState(null);
  const [error,      setError]      = useState('');

  const onDrop = useCallback(accepted => {
    if (accepted[0]) {
      setFile(accepted[0]);
      setResult(null);
      const reader = new FileReader();
      reader.onload = e => setPreview(e.target.result);
      reader.readAsDataURL(accepted[0]);
    }
  }, []);

  const { getRootProps, getInputProps, isDragActive } = useDropzone({
    onDrop,
    accept: { 'image/*': ['.jpg','.jpeg','.png','.webp'] },
    maxFiles: 1,
  });

  const handleGenerate = async () => {
    if (!file) return;
    setLoading(true); setError('');
    try {
      const form = new FormData();
      form.append('file', file);
      form.append('complainant_name', name || 'Unknown');
      form.append('incident_brief',   incident || 'Evidence submitted via Nyaya-Setu');
      const res = await axios.post('/api/evidence', form);
      setResult(res.data);
    } catch (e) {
      setError(e.response?.data?.detail || 'Certificate generation failed.');
    }
    setLoading(false);
  };

  return (
    <div>
      <h1 className="section-title" style={{ fontSize: '1.4rem', marginBottom: 8 }}>
        🔐 BSA Section 63 Evidence Certificate
      </h1>
      <p className="text-grey mb-6">
        Generate a SHA-256 cryptographic certificate for your evidence photo.
        Makes your digital evidence court-admissible under the Bharatiya Sakshya Adhiniyam 2023.
      </p>

      <div className="grid-2">
        {/* Left: Upload */}
        <div className="card">
          <div className="card-title">Upload Evidence Photo</div>
          <div {...getRootProps()} className={`upload-zone ${isDragActive ? 'drag-active' : ''}`}
               style={{ marginBottom: 16, padding: 24 }}>
            <input {...getInputProps()} />
            {preview
              ? <img src={preview} alt="preview" style={{ maxHeight: 180, maxWidth: '100%', borderRadius: 6 }} />
              : <>
                  <div className="upload-zone-icon"><Upload size={32} /></div>
                  <div className="upload-zone-text">
                    <strong>Click to upload</strong> or drag and drop<br />
                    JPG, PNG, WebP
                  </div>
                </>
            }
          </div>

          <div style={{ marginBottom: 12 }}>
            <label style={{ fontSize: '0.88rem', fontWeight: 500, display: 'block', marginBottom: 4 }}>
              Your Name (optional)
            </label>
            <input
              value={name}
              onChange={e => setName(e.target.value)}
              placeholder="Enter your name"
              style={{ width: '100%', padding: '8px 12px', border: '1px solid var(--border)', borderRadius: 'var(--radius)', fontSize: '0.9rem', outline: 'none' }}
            />
          </div>

          <div style={{ marginBottom: 16 }}>
            <label style={{ fontSize: '0.88rem', fontWeight: 500, display: 'block', marginBottom: 4 }}>
              Brief incident description
            </label>
            <textarea
              value={incident}
              onChange={e => setIncident(e.target.value)}
              placeholder="E.g., Phone snatched near Andheri station on 22 March 2026"
              rows={3}
              style={{ width: '100%', padding: '8px 12px', border: '1px solid var(--border)', borderRadius: 'var(--radius)', fontSize: '0.9rem', outline: 'none', resize: 'vertical', fontFamily: 'inherit' }}
            />
          </div>

          <button className="btn btn-primary" onClick={handleGenerate} disabled={loading || !file}
                  style={{ width: '100%', justifyContent: 'center' }}>
            <Shield size={16} />
            {loading ? 'Generating...' : 'Generate Certificate'}
          </button>
          {error && <div style={{ color: 'var(--red)', marginTop: 8, fontSize: '0.9rem' }}>⚠️ {error}</div>}
        </div>

        {/* Right: Result */}
        <div className="card">
          <div className="card-title">Certificate Details</div>

          {!result && !loading && (
            <div style={{ textAlign: 'center', padding: '40px 20px', color: 'var(--grey)' }}>
              <Shield size={48} style={{ opacity: 0.3, marginBottom: 12 }} />
              <div style={{ fontSize: '0.9rem' }}>
                Upload a photo and click Generate Certificate
              </div>
            </div>
          )}

          {loading && (
            <div className="loading">
              <div className="spinner" />
              <div>Computing SHA-256 hash...</div>
            </div>
          )}

          {result && (
            <div>
              <div style={{
                background: 'var(--ltgreen)', border: '1px solid #86EFAC',
                borderRadius: 'var(--radius)', padding: '10px 14px',
                marginBottom: 16, display: 'flex', alignItems: 'center', gap: 8,
                color: 'var(--green)', fontWeight: 600, fontSize: '0.9rem',
              }}>
                ✅ {result.verification_status}
              </div>

              {[
                { label: 'Certificate ID',   value: `NS-${result.certificate_id}` },
                { label: 'File Name',        value: result.file_name },
                { label: 'File Size',        value: `${Math.round(result.file_size_bytes/1024)} KB` },
                { label: 'Device Make',      value: result.device_make },
                { label: 'Device Model',     value: result.device_model },
                { label: 'GPS Coordinates',  value: result.gps_coordinates },
                { label: 'Captured',         value: result.capture_timestamp },
                { label: 'Legal Basis',      value: result.bsa_section },
              ].map((row, i) => (
                <div key={i} style={{
                  display: 'flex', gap: 12, padding: '6px 0',
                  borderBottom: '1px solid var(--border)', fontSize: '0.87rem',
                }}>
                  <span style={{ color: 'var(--grey)', minWidth: 130 }}>{row.label}</span>
                  <span style={{ fontWeight: 500, wordBreak: 'break-all' }}>{row.value}</span>
                </div>
              ))}

              {/* SHA-256 hash */}
              <div style={{ marginTop: 16 }}>
                <div style={{ fontSize: '0.85rem', fontWeight: 600, color: 'var(--navy)', marginBottom: 6 }}>
                  SHA-256 Hash
                </div>
                <div style={{
                  background: '#EFF6FF', border: '1px solid #BFDBFE',
                  borderRadius: 6, padding: '10px 12px',
                  fontFamily: 'monospace', fontSize: '0.78rem',
                  wordBreak: 'break-all', color: '#1E3A5F',
                }}>
                  {result.sha256_hash}
                </div>
              </div>

              <a
                href={result.pdf_download_url}
                target="_blank"
                rel="noreferrer"
                className="btn btn-primary mt-4"
                style={{ display: 'flex', justifyContent: 'center', textDecoration: 'none' }}
              >
                <Download size={16} /> Download Certificate PDF
              </a>

              <div style={{
                marginTop: 12, fontSize: '0.8rem', color: 'var(--grey)',
                padding: '8px 12px', background: 'var(--ltgrey)',
                borderRadius: 6, lineHeight: 1.6,
              }}>
                To verify: <code>sha256sum &lt;filename&gt;</code> (Linux/Mac) or{' '}
                <code>certutil -hashfile &lt;filename&gt; SHA256</code> (Windows)
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
